#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long f[100010],g[100010],jc[100010],ny[100010];
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
long long fastpow(long long x,long long y)
{
    x=(x%mod+mod)%mod;
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    jc[0]=ny[0]=1;
    for(long long i=1;i<=n+1;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[n+1]=fastpow(jc[n+1],mod-2);
    for(long long i=n;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    f[0]=1;
    f[1]=n+1;
    for(long long i=2;i<=n;i++)
    {
        f[i]=(fastpow(i,n+1)-1+mod)%mod*fastpow(i-1,mod-2)%mod;
        f[i]=(f[i]%mod+mod)%mod;
    }
    g[0]=((1-fastpow(-2,n+1))%mod+mod)%mod*fastpow(3,mod-2)%mod;
    for(long long i=1;i<=n;i++)
    {
        g[i]=((-2*g[i-1])%mod+(-fastpow(-2,n+1))%mod*C(n+1,i)%mod)*fastpow(3,mod-2)%mod;
        g[i]=(g[i]%mod+mod)%mod;
    }
    long long ans=0;
    for(long long i=0;i<=n;i++)
    {
        if(i%2==1)
        {
            ans-=f[i]*g[i]%mod;
        }
        else
        {
            ans+=f[i]*g[i]%mod;
        }
        ans=(ans%mod+mod)%mod;
    }
    printf("%lld",ans);
    return 0;
}
